### 5. Server-side service implementation

Create `ShipmentTracker/ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await db.Shipments.OrderByDescending(s => s.CreatedDate).ToListAsync();

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
        => await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
        => await db.Shipments.FindAsync(id);

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = GenerateTrackingNumber();
        shipment.CreatedDate = DateTime.UtcNow;
        shipment.Status = ShipmentStatus.Pending;
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static string GenerateTrackingNumber()
        => $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
}
```

