@page "/track"
@page "/track/{TrackingNumber}"

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment"
                    disabled="@(string.IsNullOrWhiteSpace(searchTrackingNumber) || isLoading)">
                @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<strong>@lastSearched</strong>". Please check and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.CreatedDate.ToString("MMMM d, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                @shipment.EstimatedDelivery.Value.ToString("MMMM d, yyyy")
                            }
                            else
                            {
                                <span class="text-muted">TBD</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <!-- Status progress -->
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isLoading;
    private bool searched;
    private string lastSearched = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;

        isLoading = true;
        searched = false;
        try
        {
            lastSearched = searchTrackingNumber.Trim();
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
            searched = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") _ = SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService

<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="d-flex gap-2 align-items-center">
        <label class="form-label mb-0">Filter:</label>
        <select class="form-select form-select-sm" style="width: auto;" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
        <input type="text" class="form-control form-control-sm" placeholder="Search destination..."
               style="width: 200px;" @bind="destinationFilter" @bind:event="oninput" />
    </div>
    <button class="btn btn-success btn-sm" @onclick="() => showCreateForm = !showCreateForm">
        @(showCreateForm ? "Cancel" : "+ New Shipment")
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary" @onclick="CreateShipment" disabled="@isCreating">
                        @if (isCreating) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Create Shipment
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments match the current filters.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                        </td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM d, yyyy") ?? "TBD")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <div class="btn-group btn-group-sm">
                                    <select class="form-select form-select-sm" style="width: auto;"
                                            value="@s.Status"
                                            @onchange="e => UpdateStatus(s, e)">
                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@status">@status</option>
                                        }
                                    </select>
                                </div>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3">
        @message
        <button type="button" class="btn-close" @onclick="() => message = null"></button>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private Shipment newShipment = new();
    private bool showCreateForm;
    private bool isCreating;
    private string? statusFilter;
    private string destinationFilter = string.Empty;
    private string? message;
    private bool isError;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
            .Where(s => string.IsNullOrEmpty(destinationFilter) ||
                        s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            message = "Failed to load shipments.";
            isError = true;
            shipments = [];
        }
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        try
        {
            var created = await ShipmentService.CreateShipmentAsync(newShipment);
            shipments?.Insert(0, created);
            newShipment = new();
            showCreateForm = false;
            message = $"Shipment {created.TrackingNumber} created successfully.";
            isError = false;
        }
        catch
        {
            message = "Failed to create shipment.";
            isError = true;
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            try
            {
                await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
                shipment.Status = newStatus;
                message = $"Shipment {shipment.TrackingNumber} updated to {newStatus}.";
                isError = false;
            }
            catch
            {
                message = "Failed to update status.";
                isError = true;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

