@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService

<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="d-flex gap-2 align-items-center">
        <label class="form-label mb-0">Filter:</label>
        <select class="form-select form-select-sm" style="width: auto;" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
